350→        }
351→
352→        @Override
353→        public Integer fromString(String value) throws InvalidSettingValueException {
354→            try {
355→                int number = Integer.parseInt(value);
356→                for (int validValue : values) {
357→                    if (number == validValue) {
358→                        return number;
359→                    }
360→                }
361→
362→                throw new InvalidSettingValueException();
