 15→/**
 16→ * Manager for different {@link StorageProvider} -classes that abstract access
 17→ * to sd-cards, additional internal memory and other storage-locations.
 18→ */
 19→public class StorageManager {
 20→
 21→    /**
 22→     * Provides entry points (File objects) to an underlying storage,
 23→     * alleviating the caller from having to know where that storage is located.
 24→     *
 25→     * <p>
 26→     * Allow checking for the denoted storage availability since its lifecycle
 27→     * can evolving (a storage might become unavailable at some time and be back
 28→     * online later).
 29→     * </p>
 30→     */
 31→    public interface StorageProvider {
 32→
 33→        /**
 34→         * Retrieve the uniquely identifier for the current implementation.
 35→         *
 36→         * <p>
 37→         * It is expected that the identifier doesn't change over reboots since
 38→         * it'll be used to save settings and retrieve the provider at a later
 39→         * time.
 40→         * </p>
 41→         *
 42→         * <p>
 43→         * The returned identifier doesn't have to be user friendly.
 44→         * </p>
 45→         *
 46→         * @return Never <code>null</code>.
 47→         */
 48→        String getId();
 49→
 50→        /**
 51→         * Hook point for provider initialization.
 52→         *
 53→         * @param context
 54→         *            Never <code>null</code>.
 55→         */
 56→        void init(Context context);
 57→
 58→        /**
 59→         * Some implementations may not be able to return valid File handles
 60→         * because the device doesn't provide the denoted storage. You can check
 61→         * the provider compatibility with this method to prevent from having to
 62→         * invoke this provider ever again.
 63→         *
 64→         * @param context
 65→         *            TODO
 66→         * @return Whether this provider supports the current device.
 67→         * @see StorageManager#getAvailableProviders()
 68→         */
 69→        boolean isSupported(Context context);
 70→
 71→        /**
 72→         * Return the {@link File} to the chosen email database file. The
 73→         * resulting {@link File} doesn't necessarily match an existing file on
 74→         * the filesystem.
 75→         *
 76→         * @param context
 77→         *            Never <code>null</code>.
 78→         * @param id
 79→         *            Never <code>null</code>.
 80→         * @return Never <code>null</code>.
 81→         */
 82→        File getDatabase(Context context, String id);
 83→
 84→        /**
 85→         * Return the {@link File} to the chosen attachment directory. The
 86→         * resulting {@link File} doesn't necessarily match an existing
 87→         * directory on the filesystem.
 88→         *
 89→         * @param context
 90→         *            Never <code>null</code>.
 91→         * @param id
 92→         *            Never <code>null</code>.
 93→         * @return Never <code>null</code>.
 94→         */
 95→        File getAttachmentDirectory(Context context, String id);
 96→    }
 97→
 98→    /**
 99→     * Strategy to access the always available internal storage.
100→     *
101→     * <p>
102→     * This implementation is expected to work on every device since it's based
103→     * on the regular Android API {@link Context#getDatabasePath(String)} and
104→     * uses the result to retrieve the DB path and the attachment directory path.
105→     * </p>
106→     *
107→     * <p>
108→     * The underlying storage has always been used by K-9.
109→     * </p>
110→     */
111→    public static class InternalStorageProvider implements StorageProvider {
112→        public static final String ID = "InternalStorage";
113→
114→        @Override
115→        public String getId() {
116→            return ID;
117→        }
118→
119→        @Override
120→        public void init(Context context) {
121→        }
122→
123→        @Override
124→        public boolean isSupported(Context context) {
125→            return true;
126→        }
127→
128→        @Override
129→        public File getDatabase(Context context, String id) {
130→            return context.getDatabasePath(id + ".db");
131→        }
132→
133→        @Override
134→        public File getAttachmentDirectory(Context context, String id) {
135→            // we store attachments in the database directory
136→            return context.getDatabasePath(id + ".db_att");
137→        }
138→    }
139→
140→    /**
141→     * Strategy for accessing the storage as returned by
142→     * {@link Environment#getExternalStorageDirectory()}. In order to be
143→     * compliant with Android recommendation regarding application uninstalling
144→     * and to prevent from cluttering the storage root, the chosen directory
145→     * will be
146→     * <code>&lt;STORAGE_ROOT&gt;/Android/data/&lt;APPLICATION_PACKAGE_NAME&gt;/files/</code>
147→     *
148→     * <p>
149→     * The denoted storage is usually a SD card.
150→     * </p>
151→     *
152→     * <p>
153→     * This provider is expected to work on all devices but the returned
154→     * underlying storage might not be always available, due to
155→     * mount/unmount/USB share events.
156→     * </p>
157→     */
158→    public static class ExternalStorageProvider implements StorageProvider {
159→        public static final String ID = "ExternalStorage";
160→
161→        /**
162→         * Chosen base directory.
163→         */
164→        private File mApplicationDirectory;
165→
166→
167→        @Override
168→        public String getId() {
169→            return ID;
170→        }
171→
172→        @Override
173→        public void init(Context context) {
174→            mApplicationDirectory = context.getExternalFilesDir(null);
175→        }
176→
177→        @Override
178→        public boolean isSupported(Context context) {
179→            return true;
180→        }
181→
182→        @Override
183→        public File getDatabase(Context context, String id) {
184→            return new File(mApplicationDirectory, id + ".db");
185→        }
186→
187→        @Override
188→        public File getAttachmentDirectory(Context context, String id) {
189→            return new File(mApplicationDirectory, id + ".db_att");
190→        }
191→    }
192→
193→    /**
194→     * The active storage providers.
195→     */
196→    private final Map<String, StorageProvider> mProviders = new LinkedHashMap<>();
197→
198→    protected final Context context;
199→
200→    private static transient StorageManager instance;
201→
202→    public static synchronized StorageManager getInstance(final Context context) {
203→        if (instance == null) {
204→            Context applicationContext = context.getApplicationContext();
205→            instance = new StorageManager(applicationContext);
206→        }
207→        return instance;
208→    }
209→
210→    /**
211→     * @param context
212→     *            Never <code>null</code>.
213→     * @throws NullPointerException
214→     *             If <tt>context</tt> is <code>null</code>.
215→     */
216→    protected StorageManager(final Context context) throws NullPointerException {
217→        if (context == null) {
218→            throw new NullPointerException("No Context given");
219→        }
220→
221→        this.context = context;
222→
223→        /*
224→         * 20101113/fiouzy:
225→         *
226→         * Here is where we define which providers are used, currently we only
227→         * allow the internal storage and the regular external storage.
228→         *
229→         * !!! Make sure InternalStorageProvider is the first provider as it'll
230→         * be considered as the default provider !!!
231→         */
232→        final List<StorageProvider> allProviders = Arrays.asList(
233→                new InternalStorageProvider(),
234→                new ExternalStorageProvider()
235→        );
236→        for (final StorageProvider provider : allProviders) {
237→            // check for provider compatibility
238→            if (provider.isSupported(context)) {
239→                // provider is compatible! proceeding
240→
241→                provider.init(context);
242→                mProviders.put(provider.getId(), provider);
243→            }
244→        }
245→
246→    }
247→
248→    /**
249→     * @return Never <code>null</code>.
250→     */
251→    public String getDefaultProviderId() {
252→        // assume there is at least 1 provider defined
253→        return mProviders.keySet().iterator().next();
254→    }
255→
256→    /**
257→     * @param providerId
258→     *            Never <code>null</code>.
259→     * @return <code>null</code> if not found.
260→     */
261→    protected StorageProvider getProvider(final String providerId) {
262→        return mProviders.get(providerId);
263→    }
264→
265→    /**
266→     * @param dbName
267→     *            Never <code>null</code>.
268→     * @param providerId
269→     *            Never <code>null</code>.
270→     * @return The resolved database file for the given provider ID.
271→     */
272→    public File getDatabase(final String dbName, final String providerId) {
273→        StorageProvider provider = getProvider(providerId);
274→        // TODO fallback to internal storage if no provider
275→        return provider.getDatabase(context, dbName);
276→    }
277→
278→    /**
279→     * @param dbName
280→     *            Never <code>null</code>.
281→     * @param providerId
282→     *            Never <code>null</code>.
283→     * @return The resolved attachment directory for the given provider ID.
284→     */
285→    public File getAttachmentDirectory(final String dbName, final String providerId) {
286→        StorageProvider provider = getProvider(providerId);
287→        // TODO fallback to internal storage if no provider
288→        return provider.getAttachmentDirectory(context, dbName);
289→    }
290→
291→    public Set<String> getAvailableProviders() {
292→        return mProviders.keySet();
293→    }
294→}
