import app.k9mail.legacy.account.Account
import app.k9mail.legacy.account.Account.SpecialFolderSelection
import assertk.assertThat
import assertk.assertions.isEqualTo
import com.fsck.k9.CoreResourceProvider
import com.fsck.k9.ServerSettingsSerializer
import com.fsck.k9.mail.AuthType
import com.fsck.k9.mail.ConnectionSecurity
import com.fsck.k9.mail.ServerSettings
import com.fsck.k9.mailstore.StorageManager
import org.junit.Test
import org.mockito.kotlin.doReturn
import org.mockito.kotlin.mock

class AccountPreferenceSerializerSpecialFolderImportTest {
    private val storageManager = mock<StorageManager> {
        on { defaultProviderId } doReturn DEFAULT_PROVIDER_ID
    }
    private val resourceProvider = mock<CoreResourceProvider>()
    private val serverSettingsSerializer = ServerSettingsSerializer()
    private val accountPreferenceSerializer = AccountPreferenceSerializer(
        storageManager = storageManager,
        resourceProvider = resourceProvider,
        serverSettingsSerializer = serverSettingsSerializer,
    )

    @Test
    fun `loadAccount should mark imported special folders as manual when selection key is missing`() {
        val account = createAccount()

        accountPreferenceSerializer.loadAccount(account, createStorage(includeSelections = false))

        assertManualSelections(account)
    }

    @Test
    fun `loadAccount should keep stored selection when preference entry exists`() {
        val account = createAccount()

        accountPreferenceSerializer.loadAccount(account, createStorage(includeSelections = true))

        assertThat(account.draftsFolderSelection).isEqualTo(SpecialFolderSelection.AUTOMATIC)
        assertThat(account.sentFolderSelection).isEqualTo(SpecialFolderSelection.AUTOMATIC)
        assertThat(account.trashFolderSelection).isEqualTo(SpecialFolderSelection.AUTOMATIC)
        assertThat(account.archiveFolderSelection).isEqualTo(SpecialFolderSelection.AUTOMATIC)
        assertThat(account.spamFolderSelection).isEqualTo(SpecialFolderSelection.AUTOMATIC)
    }

    private fun assertManualSelections(account: Account) {
        assertThat(account.draftsFolderSelection).isEqualTo(SpecialFolderSelection.MANUAL)
        assertThat(account.sentFolderSelection).isEqualTo(SpecialFolderSelection.MANUAL)
        assertThat(account.trashFolderSelection).isEqualTo(SpecialFolderSelection.MANUAL)
        assertThat(account.archiveFolderSelection).isEqualTo(SpecialFolderSelection.MANUAL)
        assertThat(account.spamFolderSelection).isEqualTo(SpecialFolderSelection.MANUAL)
    }

    private fun createStorage(includeSelections: Boolean): Storage {
        val values = mutableMapOf<String, String>()

        values["$ACCOUNT_UUID.${AccountPreferenceSerializer.INCOMING_SERVER_SETTINGS_KEY}"] =
            serverSettingsSerializer.serialize(createServerSettings(type = "imap", port = 993))
        values["$ACCOUNT_UUID.${AccountPreferenceSerializer.OUTGOING_SERVER_SETTINGS_KEY}"] =
            serverSettingsSerializer.serialize(createServerSettings(type = "smtp", port = 465))

        values["$ACCOUNT_UUID.email"] = "user@example.org"
        values["$ACCOUNT_UUID.accountNumber"] = "1"
        values["$ACCOUNT_UUID.inboxFolderName"] = "INBOX"
        values["$ACCOUNT_UUID.draftsFolderName"] = "Drafts"
        values["$ACCOUNT_UUID.sentFolderName"] = "Sent"
        values["$ACCOUNT_UUID.trashFolderName"] = "Trash"
        values["$ACCOUNT_UUID.archiveFolderName"] = "Archive"
        values["$ACCOUNT_UUID.spamFolderName"] = "Spam"

        if (includeSelections) {
            values["$ACCOUNT_UUID.draftsFolderSelection"] = SpecialFolderSelection.AUTOMATIC.name
            values["$ACCOUNT_UUID.sentFolderSelection"] = SpecialFolderSelection.AUTOMATIC.name
            values["$ACCOUNT_UUID.trashFolderSelection"] = SpecialFolderSelection.AUTOMATIC.name
            values["$ACCOUNT_UUID.archiveFolderSelection"] = SpecialFolderSelection.AUTOMATIC.name
